import java.util.ArrayList;import java.util.HashSet;import java.util.List;import java.util.Map;import java.util.Set;
final class ObserverPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}interface Observer{String name();void notify(String event);}record NamedObserver(String name)implements Observer{public void notify(String event){if(name.equals("failing"))throw new PatternException("observer_failed");}}
static final class Subject{final List<Observer>observers=new ArrayList<>();List<Map<String,Object>>publish(String event){List<Map<String,Object>>out=new ArrayList<>();for(Observer observer:List.copyOf(observers)){try{observer.notify(event);out.add(Map.of("event",event,"observer",observer.name(),"status","delivered"));}catch(PatternException e){out.add(Map.of("event",event,"observer",observer.name(),"status","failed","error",e.code()));}}return out;}void unsubscribe(Set<String>names){observers.removeIf(v->names.contains(v.name()));}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Subject subject=new Subject();for(Object raw:(List<Object>)input.getOrDefault("observers",List.of())){String name=String.valueOf(raw);if(!Set.of("audit","metrics","failing").contains(name))throw new PatternException("unsupported_observer");subject.observers.add(new NamedObserver(name));}List<Map<String,Object>>receipts=new ArrayList<>();List<Object>events=(List<Object>)input.getOrDefault("events",List.of());for(int i=0;i<events.size();i++){receipts.addAll(subject.publish(String.valueOf(events.get(i))));if(i==0)subject.unsubscribe(new HashSet<>((List<String>)input.getOrDefault("unsubscribe_after_first",List.of())));}return Map.of("receipts",receipts,"active",subject.observers.size());}}
